const source = $input.first().json.body ?? $input.first().json;
const requestId = typeof source.requestId === 'string' && source.requestId.trim() ? source.requestId.trim() : '';
const profile = typeof source.profile === 'string' && source.profile.trim() ? source.profile.trim() : 'acestep_turbo';
const tags = typeof source.tags === 'string' && source.tags.trim() ? source.tags.trim() : (typeof source.prompt === 'string' ? source.prompt.trim() : '');
const lyrics = typeof source.lyrics === 'string' ? source.lyrics : '';
const traceId = typeof source?.metadata?.traceId === 'string' ? source.metadata.traceId : undefined;
const language = typeof source.language === 'string' && source.language.trim() ? source.language.trim() : 'en';
const keyscale = typeof source.keyscale === 'string' && source.keyscale.trim() ? source.keyscale.trim() : 'C major';
const timesignature = typeof source.timesignature === 'string' && source.timesignature.trim() ? source.timesignature.trim() : '4';
const rawDuration = Number(source.duration ?? 120);
const rawBpm = Number(source.bpm ?? 90);
const count = source.count ?? 1;
const duration = Number.isFinite(rawDuration) ? Math.max(15, Math.min(120, Math.round(rawDuration))) : 120;
const bpm = Number.isFinite(rawBpm) ? Math.max(40, Math.min(220, Math.round(rawBpm))) : 90;
const seed = Number.isInteger(source.seed) ? source.seed : Date.now();

if (!requestId) {
  return [{ json: { requestId: null, status: 'failed', stage: 'validation', errorCode: 'MISSING_REQUEST_ID', message: 'requestId is required', responseCode: 400, route: 'error', metadata: { traceId } } }];
}
if (!tags) {
  return [{ json: { requestId, status: 'failed', stage: 'validation', errorCode: 'EMPTY_TAGS', message: 'tags or prompt is required', responseCode: 400, route: 'error', metadata: { traceId } } }];
}
if (profile !== 'acestep_turbo') {
  return [{ json: { requestId, status: 'failed', stage: 'validation', errorCode: 'UNSUPPORTED_PROFILE', message: 'profile must be acestep_turbo', responseCode: 400, route: 'error', metadata: { traceId } } }];
}
if (count !== 1) {
  return [{ json: { requestId, status: 'failed', stage: 'validation', errorCode: 'UNSUPPORTED_COUNT', message: 'count must equal 1 for v1', responseCode: 400, route: 'error', metadata: { traceId } } }];
}

const comfyWorkflow = {
  '97': { inputs: { ckpt_name: 'ace_step_1.5_turbo_aio.safetensors' }, class_type: 'CheckpointLoaderSimple', _meta: { title: 'Load Checkpoint' } },
  '94': { inputs: { tags: '', lyrics: '', seed: seed, bpm: bpm, duration: duration, timesignature: timesignature, language: language, keyscale: keyscale, generate_audio_codes: true, cfg_scale: 3, temperature: 0.75, top_p: 0.9, top_k: 0, min_p: 0, clip: ['97', 1] }, class_type: 'TextEncodeAceStepAudio1.5', _meta: { title: 'TextEncodeAceStepAudio1.5' } },
  '78': { inputs: { shift: 3, model: ['97', 0] }, class_type: 'ModelSamplingAuraFlow', _meta: { title: 'ModelSamplingAuraFlow' } },
  '18': { inputs: { samples: ['3', 0], vae: ['97', 2] }, class_type: 'VAEDecodeAudio', _meta: { title: 'VAE Decode Audio' } },
  '98': { inputs: { seconds: duration, batch_size: 1 }, class_type: 'EmptyAceStep1.5LatentAudio', _meta: { title: 'Empty Ace Step 1.5 Latent Audio' } },
  '3': { inputs: { seed: seed, steps: 15, cfg: 3, sampler_name: 'euler', scheduler: 'simple', denoise: 1, model: ['78', 0], positive: ['94', 0], negative: ['47', 0], latent_image: ['98', 0] }, class_type: 'KSampler', _meta: { title: 'KSampler' } },
  '104': { inputs: { filename_prefix: 'audio/acestep-turbo', quality: 'V0', audio: ['18', 0] }, class_type: 'SaveAudioMP3', _meta: { title: 'Save Audio (MP3)' } },
  '47': { inputs: { conditioning: ['94', 0] }, class_type: 'ConditioningZeroOut', _meta: { title: 'ConditioningZeroOut' } }
};
comfyWorkflow['94'].inputs.tags = tags;
comfyWorkflow['94'].inputs.lyrics = lyrics;

return [{ json: { requestId, profile: 'acestep_turbo', count: 1, tags, lyrics, bpm, duration, language, keyscale, timesignature, metadata: { source: source?.metadata?.source ?? 'openclaw', traceId }, workflowFile: 'music/audio_ace_step_1_5_balanced.json', comfyWorkflow, route: 'continue' } }];

const candidateItems = $input.all().filter((item) => item?.json && Object.keys(item.json).length > 0 && item.json.requestId);
const existing = candidateItems[0]?.json;
const request = $('Validate and Build Workflow').first().json;

if (existing) {
  let acceptedAt = existing.updatedAtIso;
  try {
    const result = existing.resultJson ? JSON.parse(existing.resultJson) : null;
    if (!acceptedAt && result?.acceptedAt) acceptedAt = result.acceptedAt;
  } catch {}
  return [{ json: {
    requestId: existing.requestId,
    status: existing.status || 'queued',
    jobId: existing.jobId,
    acceptedAt: acceptedAt || $now.toISO(),
    idempotentReplay: true,
    route: 'existing'
  } }];
}

return [{ json: { ...request, route: 'submit' } }];

const prepared = $('Prepare Worker Dispatch').first().json;
const response = $input.first().json;

if (!response?.accepted || response?.jobId !== prepared.jobId) {
  return [{ json: {
    requestId: prepared.requestId,
    status: 'failed',
    stage: 'dispatch',
    errorCode: 'WORKER_DISPATCH_FAILED',
    message: 'media-worker-daemon did not accept the submitted job',
    responseCode: 502,
    route: 'error',
    jobId: prepared.jobId,
    metadata: {
      traceId: prepared?.metadata?.traceId,
      response
    }
  } }];
}

return [{ json: {
  requestId: prepared.requestId,
  jobId: prepared.jobId,
  status: 'queued',
  payloadJson: prepared.payloadJson,
  resultJson: prepared.resultJson,
  updatedAtIso: prepared.acceptedAt,
  acceptedAt: prepared.acceptedAt,
  metadata: prepared.metadata,
  route: 'continue'
} }];

const item = $input.first().json;
const workerBaseUrl = (($env.MEDIA_WORKER_BASE_URL || 'https://media-worker.techmatrx.com').trim()).replace(/\/+$/, '');
const ingressToken = ($env.MEDIA_WORKER_INGRESS_TOKEN || '').trim();
if (!workerBaseUrl) {
  return [{ json: {
    requestId: item.requestId,
    status: 'failed',
    stage: 'dispatch',
    errorCode: 'MEDIA_WORKER_BASE_URL_NOT_CONFIGURED',
    message: 'MEDIA_WORKER_BASE_URL is not configured in n8n',
    responseCode: 500,
    route: 'error',
    metadata: { traceId: item?.metadata?.traceId }
  } }];
}
if (!ingressToken) {
  return [{ json: {
    requestId: item.requestId,
    status: 'failed',
    stage: 'dispatch',
    errorCode: 'MEDIA_WORKER_INGRESS_TOKEN_NOT_CONFIGURED',
    message: 'MEDIA_WORKER_INGRESS_TOKEN is not configured in n8n',
    responseCode: 500,
    route: 'error',
    metadata: { traceId: item?.metadata?.traceId }
  } }];
}
const jobId = `job_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
const acceptedAt = $now.toISO();
const payloadJson = JSON.stringify({
  profile: item.profile,
  count: item.count,
  tags: item.tags,
  lyrics: item.lyrics,
  bpm: item.bpm,
  duration: item.duration,
  language: item.language,
  keyscale: item.keyscale,
  timesignature: item.timesignature,
  metadata: item.metadata,
  workflowFile: item.workflowFile
});
const resultJson = JSON.stringify({
  provider: 'media-worker-daemon',
  traceId: item?.metadata?.traceId,
  acceptedAt,
  status: 'queued'
});
return [{ json: {
  ...item,
  jobId,
  acceptedAt,
  payloadJson,
  resultJson,
  dispatchUrl: `${workerBaseUrl}/jobs`,
  workerDispatchBody: {
    jobId,
    requestId: item.requestId,
    profile: item.profile,
    payload: {
      workflow: item.comfyWorkflow,
      workflowFile: item.workflowFile,
      metadata: item.metadata
    }
  },
  route: 'continue'
} }];

const request = $('Validate and Build Workflow').first().json;
const now = Date.now();
const maxAgeMs = Number($env.MEDIA_WORKER_HEARTBEAT_MAX_AGE_MS || 180000);
const requiredMediaType = 'audio';
const requiredProfile = request.profile || 'acestep_turbo';

function list(value) {
  return String(value || '')
    .split(',')
    .map((entry) => entry.trim())
    .filter(Boolean);
}

function isFresh(worker) {
  const updatedAt = Date.parse(worker.updatedAtIso || worker.updatedAt || worker.createdAt || '');
  return Number.isFinite(updatedAt) && now - updatedAt <= maxAgeMs;
}

const workers = $input.all()
  .map((item) => item.json || {})
  .filter((worker) => worker.workerId)
  .filter((worker) => worker.status === 'ok')
  .filter((worker) => !worker.drain)
  .filter((worker) => Boolean(worker.capacityAvailable))
  .filter((worker) => Number(worker.activeJobs || 0) < Number(worker.maxConcurrentJobs || 0))
  .filter((worker) => Boolean(worker.comfyReachable))
  .filter((worker) => list(worker.supportedMediaTypes).includes(requiredMediaType))
  .filter((worker) => list(worker.supportedProfiles).includes(requiredProfile))
  .filter(isFresh)
  .sort((a, b) => Number(a.activeJobs || 0) - Number(b.activeJobs || 0));

const selectedWorker = workers[0];
if (!selectedWorker) {
  return [{ json: {
    ...request,
    status: 'failed',
    stage: 'worker_selection',
    errorCode: 'NO_READY_WORKER',
    message: 'No ready media worker is available for this request',
    responseCode: 503,
    route: 'error',
    workerSelection: {
      requiredMediaType,
      requiredProfile,
      maxAgeMs,
      observedWorkers: $input.all().map((item) => ({
        workerId: item.json?.workerId,
        status: item.json?.status,
        drain: item.json?.drain,
        activeJobs: item.json?.activeJobs,
        maxConcurrentJobs: item.json?.maxConcurrentJobs,
        capacityAvailable: item.json?.capacityAvailable,
        comfyReachable: item.json?.comfyReachable,
        updatedAtIso: item.json?.updatedAtIso
      }))
    },
    metadata: request.metadata
  } }];
}

return [{ json: {
  ...request,
  route: 'continue',
  selectedWorker: {
    workerId: selectedWorker.workerId,
    status: selectedWorker.status,
    activeJobs: selectedWorker.activeJobs,
    maxConcurrentJobs: selectedWorker.maxConcurrentJobs,
    updatedAtIso: selectedWorker.updatedAtIso,
    rabbitmqEnabled: selectedWorker.rabbitmqEnabled,
    rabbitmqQueue: selectedWorker.rabbitmqQueue
  }
} }];
